class Solution:
    def minOperations(self, nums, x, k):
        n = len(nums)
        costs = []
        for i in range(n - x + 1):
            window = sorted(nums[i:i + x])
            med = window[len(window) // 2]
            costs.append(sum(abs(v - med) for v in window))
        m = len(costs)
        INF = float('inf')
        best = [INF]
        def rec(i, chosen, acc):
            if acc >= best[0]:
                return
            if chosen == k:
                if acc < best[0]:
                    best[0] = acc
                return
            if i > m - 1:
                return
            rec(i + 1, chosen, acc)
            rec(i + x, chosen + 1, acc + costs[i])
        rec(0, 0, 0)
        return best[0]

