import heapq
from collections import defaultdict

class _SlidingMedian:
    def __init__(self):
        self.lo, self.hi = [], []
        self.delayed = defaultdict(int)
        self.lo_size = self.hi_size = 0
        self.sum_lo = self.sum_hi = 0

    def _prune(self, heap, is_lo):
        while heap:
            v = -heap[0] if is_lo else heap[0]
            if self.delayed[v] > 0:
                self.delayed[v] -= 1
                heapq.heappop(heap)
            else:
                break

    def add(self, num):
        if self.lo and num <= -self.lo[0]:
            heapq.heappush(self.lo, -num)
            self.lo_size += 1
            self.sum_lo += num
        else:
            heapq.heappush(self.hi, num)
            self.hi_size += 1
            self.sum_hi += num
        self._rebalance()

    def remove(self, num):
        self.delayed[num] += 1
        if self.lo and num <= -self.lo[0]:
            self.lo_size -= 1
            self.sum_lo -= num
            if num == -self.lo[0]:
                self._prune(self.lo, True)
        else:
            self.hi_size -= 1
            self.sum_hi -= num
            if self.hi and num == self.hi[0]:
                self._prune(self.hi, False)
        self._rebalance()

    def _rebalance(self):
        if self.lo_size > self.hi_size + 1:
            v = -heapq.heappop(self.lo)
            self.lo_size -= 1
            self.sum_lo -= v
            heapq.heappush(self.hi, v)
            self.hi_size += 1
            self.sum_hi += v
            self._prune(self.lo, True)
        elif self.hi_size > self.lo_size:
            v = heapq.heappop(self.hi)
            self.hi_size -= 1
            self.sum_hi -= v
            heapq.heappush(self.lo, -v)
            self.lo_size += 1
            self.sum_lo += v
            self._prune(self.hi, False)
        self._prune(self.lo, True)
        self._prune(self.hi, False)

    def cost(self):
        med = -self.lo[0]
        return (med * self.lo_size - self.sum_lo) + (self.sum_hi - med * self.hi_size)

class Solution:
    def minOperations(self, nums, x, k):
        n = len(nums)
        sm = _SlidingMedian()
        costs = [0] * (n - x + 1)
        for i in range(x):
            sm.add(nums[i])
        costs[0] = sm.cost()
        for i in range(x, n):
            sm.add(nums[i])
            sm.remove(nums[i - x])
            costs[i - x + 1] = sm.cost()
        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            row, prev_row = dp[i], dp[i - 1]
            for j in range(0, k + 1):
                best = prev_row[j]
                if j >= 1 and i >= x:
                    cand = dp[i - x][j - 1] + costs[i - x]
                    if cand < best:
                        best = cand
                row[j] = best
        return dp[n][k]

