class MinHeap {
    constructor() { this.a = []; }
    size() { return this.a.length; }
    peek() { return this.a[0]; }
    push(v) {
        const a = this.a;
        a.push(v);
        let i = a.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (a[p] <= a[i]) break;
            const tmp = a[p]; a[p] = a[i]; a[i] = tmp;
            i = p;
        }
    }
    pop() {
        const a = this.a;
        const top = a[0];
        const last = a.pop();
        if (a.length > 0) {
            a[0] = last;
            let i = 0;
            const n = a.length;
            while (true) {
                const l = 2 * i + 1, r = 2 * i + 2;
                let smallest = i;
                if (l < n && a[l] < a[smallest]) smallest = l;
                if (r < n && a[r] < a[smallest]) smallest = r;
                if (smallest === i) break;
                const tmp = a[i]; a[i] = a[smallest]; a[smallest] = tmp;
                i = smallest;
            }
        }
        return top;
    }
}

var minOperations = function(nums, x, k) {
    const n = nums.length;
    const lo = new MinHeap(), hi = new MinHeap();
    const delayed = new Map();
    let loSize = 0, hiSize = 0, sumLo = 0, sumHi = 0;
    const getD = (key) => delayed.get(key) || 0;
    function pruneLo() {
        while (lo.size() > 0) {
            const v = -lo.peek();
            if (getD(v) > 0) { delayed.set(v, getD(v) - 1); lo.pop(); } else break;
        }
    }
    function pruneHi() {
        while (hi.size() > 0) {
            const v = hi.peek();
            if (getD(v) > 0) { delayed.set(v, getD(v) - 1); hi.pop(); } else break;
        }
    }
    function rebalance() {
        if (loSize > hiSize + 1) {
            const v = -lo.pop();
            loSize--; sumLo -= v;
            hi.push(v); hiSize++; sumHi += v;
            pruneLo();
        } else if (hiSize > loSize) {
            const v = hi.pop();
            hiSize--; sumHi -= v;
            lo.push(-v); loSize++; sumLo += v;
            pruneHi();
        }
        pruneLo();
        pruneHi();
    }
    function add(num) {
        if (lo.size() > 0 && num <= -lo.peek()) {
            lo.push(-num); loSize++; sumLo += num;
        } else {
            hi.push(num); hiSize++; sumHi += num;
        }
        rebalance();
    }
    function remove(num) {
        delayed.set(num, getD(num) + 1);
        if (lo.size() > 0 && num <= -lo.peek()) {
            loSize--; sumLo -= num;
            if (num === -lo.peek()) pruneLo();
        } else {
            hiSize--; sumHi -= num;
            if (hi.size() > 0 && num === hi.peek()) pruneHi();
        }
        rebalance();
    }
    function windowCost() {
        const med = -lo.peek();
        return (med * loSize - sumLo) + (sumHi - med * hiSize);
    }
    const costs = new Array(n - x + 1);
    for (let i = 0; i < x; i++) add(nums[i]);
    costs[0] = windowCost();
    for (let i = x; i < n; i++) {
        add(nums[i]);
        remove(nums[i - x]);
        costs[i - x + 1] = windowCost();
    }
    const INF = Infinity;
    const dp = new Array(n + 1);
    for (let i = 0; i <= n; i++) dp[i] = new Array(k + 1).fill(INF);
    dp[0][0] = 0;
    for (let i = 1; i <= n; i++) {
        for (let j = 0; j <= k; j++) {
            let best = dp[i - 1][j];
            if (j >= 1 && i >= x) {
                const cand = dp[i - x][j - 1] + costs[i - x];
                if (cand < best) best = cand;
            }
            dp[i][j] = best;
        }
    }
    return dp[n][k];
};
